features.snippet:
parameter int SEL = 0;
generate
  if (SEL == 0)      sub_a inst_a();
  else if (SEL == 1) sub_b inst_b();
  else if (SEL == 2) sub_c inst_c();
  else               sub_d inst_d();
endgenerate

parameter int SEL = 2;
generate
  case (SEL)
    0: sub0 i0();
    1: sub1 i1();
    2: sub2 i2();
    3: sub3 i3();
    default: sub4 i4();
  endcase
endgenerate

// Level 2 module: two generate branches
module level2 #(parameter int D = 0)();
  generate
    if (D == 0) leaf l0();
    else        leaf l1();
  endgenerate
endmodule
// Level 1 module: two generate branches, each instantiates level2
module level1 #(parameter int D = 0)();
  generate
    if (D == 0) level2 #(0) n0();
    else        level2 #(1) n1();
  endgenerate
endmodule

parameter int EN = 1;
module dead_sub();
  generate
    if (1) logic x;
    else   logic y;
  endgenerate
endmodule
generate
  if (EN) logic active_sig;
  else    dead_sub ds();
endgenerate
